const body = $input.first().json.body || {};
const action = String(body.action || '').trim().toLowerCase();
const target = String(body.target || '').trim();
const operator = String(body.operator || 'unknown').trim();
const validActions = ['isolate', 'quarantine', 'restore'];
if (!action || !target) {
  return [{ json: { valid: false, error: 'Missing action or target parameter' } }];
}
if (!validActions.includes(action)) {
  return [{ json: { valid: false, error: `Invalid action: ${action}` } }];
}
return [{ json: { valid: true, action, target, operator, timestamp: new Date().toISOString() } }];

const context = $('Validate Input').first().json;
const resp = $input.first().json;
const result = (resp.results || [])[0] || { columns: [], data: [] };
if (!result.data || result.data.length === 0) {
  return [{ json: { found: false, error: `Service '${context.target}' not found` } }];
}
const row = result.data[0].row;
return [{ json: { found: true, action: context.action, operator: context.operator, timestamp: context.timestamp, service: row[0], current_status: row[1], server: row[2], server_ip: row[3], upstream_services: row[4] || [] } }];

const d = $input.first().json;
const rule = d.action === 'restore' ? 'ALLOW' : 'DENY';
return [{ json: { ...d, firewall: { rule, target_ip: d.server_ip, port: 8080, status: 'executed' } } }];

const d = $('Simulate Firewall Action').first().json;
const status = d.action === 'restore' ? 'active' : 'quarantined';
const warning = d.upstream_services && d.upstream_services.filter(Boolean).length ? ` Upstream services: ${d.upstream_services.filter(Boolean).join(', ')}.` : '';
return [{ json: { success: true, action: d.action, service: d.service, new_status: status, server: d.server, firewall: d.firewall, operator: d.operator, timestamp: d.timestamp, message: `Remediation executed: ${d.action} ${d.service}. Firewall rule ${d.firewall.rule} ${d.firewall.target_ip}:${d.firewall.port}. Graph status -> ${status}.${warning}` } }];
